import logging
import textwrap
from pathlib import Path

import click

from tim.cliagent import CliAgent
from tim import MacSandboxProject


def _configure_logging(verbosity: int) -> None:
    if verbosity == 0:
        return
    log_level = logging.INFO
    if verbosity > 1:
        log_level = logging.DEBUG
    stream_handler = logging.StreamHandler()
    stream_handler.addFilter(lambda record: record.name.startswith("tim."))
    stream_handler.setLevel(log_level)
    logging.basicConfig(level=log_level, handlers=[stream_handler])


def _parse_log_file(log_path: Path) -> list[dict]:
    messages: list[dict] = []
    with open(log_path, "r", encoding="utf-8") as file_handle:
        for line in file_handle:
            stripped_line = line.strip()
            if not stripped_line:
                continue
            record = json.loads(stripped_line)
            messages.append(record)
    return messages


def _escape_html(text: str) -> str:
    return (
        text.replace("&", "&amp;")
        .replace("<", "&lt;")
        .replace(">", "&gt;")
        .replace('"', "&quot;")
        .replace("'", "&#x27;")
    )


def _format_timestamp(at_value: str) -> str:
    if at_value and len(at_value) >= 19:
        return at_value[:19].replace("T", " ")
    return at_value


def _render_role_badge(role: str) -> str:
    role_classes: dict[str, str] = {
        "system": "role-system",
        "user": "role-user",
        "assistant": "role-assistant",
        "tool": "role-tool",
    }
    css_class = role_classes.get(role, "role-unknown")
    return f'<span class="{css_class}">{_escape_html(role)}</span>'


def _render_tool_call_arguments(arguments_str: str) -> str:
    try:
        arguments = json.loads(arguments_str)
        pretty = json.dumps(arguments, indent=2, ensure_ascii=False)
        return _escape_html(pretty)
    except (json.JSONDecodeError, TypeError):
        return _escape_html(arguments_str)


def _render_tool_calls(tool_calls: list[dict]) -> str:
    blocks = []
    for call in tool_calls:
        call_id = _escape_html(call.get("id", ""))
        call_name = _escape_html(call.get("name", ""))
        arguments_str = call.get("arguments", "{}")
        formatted_args = _render_tool_call_arguments(arguments_str)
        block = (
            f'<div class="tool-call">'
            f'<span class="tool-call-id">[{call_id}]</span>'
            f'<span class="tool-call-name">{call_name}</span>'
            f'<pre class="tool-call-args">{formatted_args}</pre>'
            f"</div>"
        )
        blocks.append(block)
    return "\n".join(blocks)


def _render_reasoning(reasoning_text: str) -> str:
    escaped = _escape_html(reasoning_text)
    return (
        f'<details class="reasoning-block">'
        f'<summary>Reasoning</summary>'
        f'<div class="reasoning-content">{escaped}</div>'
        f"</details>"
    )


def _render_message_content(content: str) -> str:
    if not content:
        return "<p class=\"empty-content\">(empty)</p>"
    escaped = _escape_html(content)
    return f"<div class=\"message-content\">{escaped}</div>"


def _render_tool_output(content: str, call_id: str) -> str:
    escaped = _escape_html(content)
    id_display = _escape_html(call_id)
    return (
        f'<details class="tool-output-block">'
        f'<summary>Tool Output [{id_display}]</summary>'
        f'<pre class="tool-output-content">{escaped}</pre>'
        f"</details>"
    )


def _render_message(record: dict) -> str:
    message = record.get("message", {})
    role = message.get("role", "unknown")
    timestamp = _format_timestamp(record.get("at", ""))
    badge = _render_role_badge(role)
    parts: list[str] = []

    if role == "assistant":
        content = message.get("content", "")
        reasoning = message.get("reasoning", "")
        tool_calls = message.get("tool_calls", [])

        if reasoning:
            parts.append(_render_reasoning(reasoning))
        if content:
            parts.append(_render_message_content(content))
        if tool_calls:
            parts.append(_render_tool_calls(tool_calls))

    elif role == "tool":
        content = message.get("content", "")
        call_id = message.get("id", "")
        if content:
            parts.append(_render_tool_output(content, call_id))
        else:
            parts.append("<p class=\"empty-content\">(empty output)</p>")

    elif role == "system":
        parts.append(_render_message_content(message.get("content", "")))

    elif role == "user":
        parts.append(_render_message_content(message.get("content", "")))

    else:
        parts.append(_render_message_content(message.get("content", "")))

    rendered_parts = "\n".join(parts)
    return (
        f'<div class="message" data-role="{role}">'
        f'<div class="message-header">'
        f'<span class="message-timestamp">{_escape_html(timestamp)}</span>'
        f"{badge}"
        f"</div>"
        f"<div class=\"message-body\">{rendered_parts}</div>"
        f"</div>"
    )


def _build_html(messages: list[dict]) -> str:
    message_blocks = []
    for record in messages:
        message_blocks.append(_render_message(record))

    html_body = "\n".join(message_blocks)
    return textwrap.dedent("""\
