@click.command()
@click.argument("log_path", type=click.Path(exists=True))
@click.option("--output", "-o", type=click.Path(), default=None, help="Output HTML file path")
def log(log_path: str, output: str | None) -> None:
    log_file = Path(log_path)
    if output:
        output_path = Path(output)
    else:
        output_path = log_file.with_suffix(".html")
    messages = _parse_log_file(log_file)
    html_content = _build_html(messages)
    output_path.write_text(html_content, encoding="utf-8")
    click.echo(f"Wrote {output_path}")


@click.group(invoke_without_command=True)
@click.option("-v", "--verbose", count=True, default=0)
def main(verbose: int) -> None:
    _configure_logging(verbose)
    ctx = click.get_current_context()

    if ctx.invoked_subcommand is None:
        project = MacSandboxProject.cwd()
        agent = CliAgent(project)
        agent.run_forever()


@main.command()
def run() -> None:
    print("run subcommand invoked")
