56	        .replace(">", "&gt;")
57	        .replace('"', "&quot;")
58	        .replace("'", "&#x27;")
59	    )
60	
61	
62	def _format_timestamp(at_value: str) -> str:
63	    if at_value and len(at_value) >= 19:
64	        return at_value[:19].replace("T", " ")
65	    return at_value
66	
67	
68	def _render_role_badge(role: str) -> str:
69	    role_classes: dict[str, str] = {
70	        "system": "role-system",
71	        "user": "role-user",
72	        "assistant": "role-assistant",
73	        "tool": "role-tool",
74	    }
75	    css_class = role_classes.get(role, "role-unknown")
76	    return f'<span class="{css_class}">{_escape_html(role)}</span>'
77	
78	
79	def _render_tool_call_arguments(arguments_str: str) -> str:
80	    try:
81	        arguments = json.loads(arguments_str)
82	        pretty = json.dumps(arguments, indent=2, ensure_ascii=False)
83	        return _escape_html(pretty)
84	    except (json.JSONDecodeError, TypeError):
85	        return _escape_html(arguments_str)
86	
87	
88	def _render_tool_calls(tool_calls: list[dict]) -> str:
89	    blocks = []
90	    for call in tool_calls:
91	        call_id = _escape_html(call.get("id", ""))
92	        call_name = _escape_html(call.get("name", ""))
93	        arguments_str = call.get("arguments", "{}")
94	        formatted_args = _render_tool_call_arguments(arguments_str)
95	        block = (
96	            f'<div class="tool-call">'
97	            f'<span class="tool-call-id">[{call_id}]</span>'
98	            f'<span class="tool-call-name">{call_name}</span>'
99	            f'<pre class="tool-call-args">{formatted_args}</pre>'
100	            f"</div>"
101	        )
102	        blocks.append(block)
103	    return "\n".join(blocks)
104	
105	
106	def _render_reasoning(reasoning_text: str) -> str:
107	    escaped = _escape_html(reasoning_text)
108	    return (
109	        f'<details class="reasoning-block">'
110	        f"<summary>Reasoning</summary>"
111	        f'<div class="reasoning-content">{escaped}</div>'
112	        f"</details>"
113	    )
114	
115	
116	def _render_message_content(content: str) -> str:
117	    if not content:
118	        return '<p class="empty-content">(empty)</p>'
119	    escaped = _escape_html(content)
120	    return f'<div class="message-content">{escaped}</div>'
121	
122	
123	def _render_tool_output(content: str, call_id: str) -> str:
124	    escaped = _escape_html(content)
125	    id_display = _escape_html(call_id)
126	    return (
127	        f'<details class="tool-output-block">'
128	        f"<summary>Tool Output [{id_display}]</summary>"
129	        f'<pre class="tool-output-content">{escaped}</pre>'
130	        f"</details>"
131	    )
132	
133	
134	def _render_message(record: dict) -> str:
135	    message = record.get("message", {})
136	    role = message.get("role", "unknown")
137	    timestamp = _format_timestamp(record.get("at", ""))
138	    badge = _render_role_badge(role)
139	    parts: list[str] = []
140	
141	    if role == "assistant":
142	        content = message.get("content", "")
143	        reasoning = message.get("reasoning", "")
144	        tool_calls = message.get("tool_calls", [])
145	
146	        if reasoning:
147	            parts.append(_render_reasoning(reasoning))
148	        if content:
149	            parts.append(_render_message_content(content))
150	        if tool_calls:
151	            parts.append(_render_tool_calls(tool_calls))
152	
153	    elif role == "tool":
154	        content = message.get("content", "")
155	        call_id = message.get("id", "")
156	        if content:
157	            parts.append(_render_tool_output(content, call_id))
158	        else:
159	            parts.append('<p class="empty-content">(empty output)</p>')
160	
161	    elif role == "system":
162	        parts.append(_render_message_content(message.get("content", "")))
163	
164	    elif role == "user":
165	        parts.append(_render_message_content(message.get("content", "")))
166	
167	    else:
168	        parts.append(_render_message_content(message.get("content", "")))
169	
170	    rendered_parts = "\n".join(parts)
171	    return (
172	        f'<div class="message" data-role="{role}">'
173	        f'<div class="message-header">'
174	        f'<span class="message-timestamp">{_escape_html(timestamp)}</span>'
175	        f"{badge}"
176	        f"</div>"
177	        f'<div class="message-body">{rendered_parts}</div>'
178	        f"</div>"
179	    )
