340	def _build_html(messages: list[dict]) -> str:
341	    message_blocks = []
342	    for record in messages:
343	        message_blocks.append(_render_message(record))
344	
345	    html_body = "\n".join(message_blocks)
346	    return (
347	        "<!DOCTYPE html>\n"
348	        '<html lang="en">\n'
349	        "<head>\n"
350	        '    <meta charset="UTF-8">\n'
351	        '    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n'
352	        "    <title>Agent Log</title>\n"
353	        "    <style>\n"
354	        f"{_CSS.strip()}\n"
355	        "    </style>\n"
356	        "</head>\n"
357	        "<body>\n"
358	        "    <h1>Agent Log</h1>\n"
359	        f"    {html_body}\n"
360	        "</body>\n"
361	        "</html>\n"
362	    )
