367	@click.option("--output", "-o", type=click.Path(), default=None, help="Output HTML file path")
368	def log(log_path: str, output: str | None) -> None:
369	    log_file = Path(log_path)
370	    if output:
371	        output_path = Path(output)
372	    else:
373	        output_path = log_file.with_suffix(".html")
374	    messages = _parse_log_file(log_file)
375	    html_content = _build_html(messages)
376	    output_path.write_text(html_content, encoding="utf-8")
377	    click.echo(f"Wrote {output_path}")
